 1	import * as React from 'react';
 2	import { humanizeBinaryBytes } from '@odf/shared/utils';
 3	import { observer } from 'mobx-react-lite';
 4	import {
 5	  Button,
 6	  ButtonVariant,
 7	  Flex,
 8	  FlexItem,
 9	  Icon,
10	  ProgressMeasureLocation,
11	  Progress,
12	  ProgressVariant,
13	} from '@patternfly/react-core';
14	import { CloseIcon, FileIcon } from '@patternfly/react-icons';
15	import { uploadStore } from '../store';
16	import { UploadStatus } from '../types';
17	import './uploadStatusItem.scss';
18	
19	type UploadStatusItemProps = {
20	  fileName: string;
21	  fileSize: string;
22	  progress: number;
23	  failed: boolean;
24	  itemKey: string;
25	};
26	
27	const getProgressVariant = (
28	  state: UploadStatus
29	): Progress['props']['variant'] => {
30	  switch (state) {
31	    case UploadStatus.UPLOAD_FAILED:
32	    case UploadStatus.UPLOAD_CANCELLED:
33	      return ProgressVariant.danger;
34	    case UploadStatus.UPLOAD_COMPLETE:
35	      return ProgressVariant.success;
36	    default:
37	      return undefined;
38	  }
39	};
40	
41	const FileTitle: React.FC<{
42	  name: string;
43	  size: string;
44	  onAbort?: (fileName: string) => void;
45	}> = ({ name, size }) => (
46	  <div>
47	    <span className="odf-upload-status-item__file-title--overflow">{name}</span>
48	    &nbsp;
49	    <span className="odf-upload-status-item__file-title--color ">{size}</span>
50	  </div>
51	);
52	
53	export const UploadStatusItem: React.FC<UploadStatusItemProps> = observer(
54	  ({ fileName, failed, itemKey }) => {
55	    const item = uploadStore.getFile(itemKey);
56	    const onAbort = () => uploadStore.performAbort(itemKey);
57	    const progress = (item.loaded / item.total) * 100;
58	    const variant = getProgressVariant(item.uploadState);
59	    return (
60	      <Flex>
61	        <FlexItem>
62	          <Icon size="md">
63	            <FileIcon />
64	          </Icon>
65	        </FlexItem>
66	        <FlexItem grow={{ default: 'grow' }}>
67	          <Progress
68	            measureLocation={ProgressMeasureLocation.top}
69	            variant={variant}
70	            value={progress}
71	            title={
72	              <FileTitle
73	                name={fileName}
74	                size={humanizeBinaryBytes(item.total).string}
75	              />
76	            }
77	          />
78	        </FlexItem>
79	        <FlexItem>
80	          {progress !== 100 && !failed && (
81	            <Button onClick={onAbort} variant={ButtonVariant.plain}>
82	              <CloseIcon />
83	            </Button>
84	          )}
85	        </FlexItem>
86	      </Flex>
87	    );
88	  }
89	);

